package com.example.umnapps;

import android.app.Dialog;
import android.content.Context;
import android.graphics.Color;
import android.graphics.drawable.ColorDrawable;
import android.graphics.drawable.Drawable;
import android.view.Gravity;
import android.view.ViewGroup;
import android.view.Window;
import android.view.WindowInsetsController;
import android.view.WindowManager;
import android.widget.FrameLayout;
import android.widget.ImageView;

/**
 * Helper class untuk menampilkan gambar dalam dialog fullscreen
 * dengan kemampuan pinch-to-zoom dan double-tap-to-zoom.
 */
public class ImagePopupHelper {

    /**
     * Menampilkan popup fullscreen dari sebuah ImageView yang di-klik.
     * Gambar bisa di-zoom dengan pinch atau double-tap.
     *
     * @param context Context activity
     * @param sourceImageView ImageView sumber yang akan ditampilkan
     */
    public static void show(Context context, ImageView sourceImageView) {
        Drawable drawable = sourceImageView.getDrawable();
        if (drawable == null) return;

        Dialog dialog = new Dialog(context, android.R.style.Theme_Black_NoTitleBar_Fullscreen);
        dialog.requestWindowFeature(Window.FEATURE_NO_TITLE);
        dialog.setCancelable(true);

        // Root layout dengan background semi-transparan gelap
        FrameLayout rootLayout = new FrameLayout(context);
        rootLayout.setBackgroundColor(Color.parseColor("#E6000000")); // 90% opacity black
        rootLayout.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT));

        // Zoomable image
        ZoomableImageView zoomableImage = new ZoomableImageView(context);
        zoomableImage.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT));
        Drawable.ConstantState cs = drawable.getConstantState();
        if (cs != null) {
            zoomableImage.setImageDrawable(cs.newDrawable().mutate());
        } else {
            zoomableImage.setImageDrawable(drawable);
        }

        // Close button (X) di pojok kanan atas
        ImageView closeButton = new ImageView(context);
        FrameLayout.LayoutParams closeParams = new FrameLayout.LayoutParams(
                dpToPx(context, 40),
                dpToPx(context, 40));
        closeParams.gravity = Gravity.TOP | Gravity.END;
        closeParams.topMargin = dpToPx(context, 45);
        closeParams.rightMargin = dpToPx(context, 20);
        closeButton.setLayoutParams(closeParams);
        closeButton.setImageResource(android.R.drawable.ic_menu_close_clear_cancel);
        closeButton.setColorFilter(Color.WHITE);
        closeButton.setPadding(
                dpToPx(context, 8),
                dpToPx(context, 8),
                dpToPx(context, 8),
                dpToPx(context, 8));
        closeButton.setBackground(createCircleBackground());
        closeButton.setElevation(dpToPx(context, 4));
        closeButton.setClickable(true);
        closeButton.setFocusable(true);

        // Hint text "Pinch untuk zoom • Tap 2x untuk reset"
        android.widget.TextView hintText = new android.widget.TextView(context);
        FrameLayout.LayoutParams hintParams = new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.WRAP_CONTENT,
                ViewGroup.LayoutParams.WRAP_CONTENT);
        hintParams.gravity = Gravity.BOTTOM | Gravity.CENTER_HORIZONTAL;
        hintParams.bottomMargin = dpToPx(context, 30);
        hintText.setLayoutParams(hintParams);
        hintText.setText("Pinch untuk zoom  •  Tap 2x untuk reset");
        hintText.setTextColor(Color.parseColor("#99FFFFFF")); // 60% white
        hintText.setTextSize(12);

        // Add views
        rootLayout.addView(zoomableImage);
        rootLayout.addView(closeButton);
        rootLayout.addView(hintText);

        dialog.setContentView(rootLayout);

        // Close on button click
        closeButton.setOnClickListener(v -> dialog.dismiss());

        // Make dialog fullscreen
        Window window = dialog.getWindow();
        if (window != null) {
            window.setLayout(WindowManager.LayoutParams.MATCH_PARENT,
                    WindowManager.LayoutParams.MATCH_PARENT);
            window.setBackgroundDrawable(new ColorDrawable(Color.TRANSPARENT));
            // Hide system bars for immersive experience (API 30+)
            WindowInsetsController controller = window.getInsetsController();
            if (controller != null) {
                controller.hide(android.view.WindowInsets.Type.systemBars());
                controller.setSystemBarsBehavior(
                        WindowInsetsController.BEHAVIOR_SHOW_TRANSIENT_BARS_BY_SWIPE);
            }
        }

        // Fade-in hint lalu hilangkan setelah 3 detik
        hintText.setAlpha(0f);
        hintText.animate().alpha(1f).setDuration(300).start();
        hintText.postDelayed(() -> hintText.animate().alpha(0f).setDuration(500).start(), 3000);

        dialog.show();
    }

    /**
     * Buat click listener untuk ImageView agar bisa popup zoom.
     */
    public static void makeZoomable(Context context, ImageView imageView) {
        imageView.setClickable(true);
        imageView.setFocusable(true);
        imageView.setOnClickListener(v -> show(context, imageView));
    }

    private static int dpToPx(Context context, int dp) {
        return (int) (dp * context.getResources().getDisplayMetrics().density);
    }

    private static android.graphics.drawable.GradientDrawable createCircleBackground() {
        android.graphics.drawable.GradientDrawable shape = new android.graphics.drawable.GradientDrawable();
        shape.setShape(android.graphics.drawable.GradientDrawable.OVAL);
        shape.setColor(Color.parseColor("#66000000")); // semi-transparent black
        return shape;
    }
}

package com.example.umnapps;

import android.content.Intent;
import android.os.Bundle;
import android.widget.ImageView;
import android.widget.LinearLayout;
import androidx.appcompat.app.AppCompatActivity;

public class JalurAkademikActivity extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_jalur_akademik);

        ImageView btnBack = findViewById(R.id.btnBack);
        LinearLayout navHome = findViewById(R.id.navHome);
        LinearLayout navProfil = findViewById(R.id.navProfil);
        LinearLayout navFakultas = findViewById(R.id.navFakultas);
        LinearLayout navFasilitas = findViewById(R.id.navFasilitas);

        if (btnBack != null) btnBack.setOnClickListener(v -> finish());

        if (navHome != null) navHome.setOnClickListener(v -> {
            Intent intent = new Intent(this, HomeActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
            startActivity(intent);
        });

        if (navProfil != null) navProfil.setOnClickListener(v -> {
            startActivity(new Intent(this, ProfilActivity.class));
        });

        if (navFakultas != null) navFakultas.setOnClickListener(v -> {
            startActivity(new Intent(this, FakultasActivity.class));
        });

        if (navFasilitas != null) navFasilitas.setOnClickListener(v -> {
            startActivity(new Intent(this, FasilitasActivity.class));
        });
    }
}

package com.example.umnapps;

import android.content.Intent;
import android.os.Bundle;
import android.widget.ImageView;
import android.widget.LinearLayout;
import androidx.appcompat.app.AppCompatActivity;

public class JalurAkademikActivity extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_jalur_akademik);

        ImageView btnBack = findViewById(R.id.btnBack);
        LinearLayout navHome = findViewById(R.id.navHome);
        LinearLayout navProfil = findViewById(R.id.navProfil);
        LinearLayout navFakultas = findViewById(R.id.navFakultas);
        LinearLayout navFasilitas = findViewById(R.id.navFasilitas);

        if (btnBack != null) btnBack.setOnClickListener(v -> finish());

        if (navHome != null) navHome.setOnClickListener(v -> {
            Intent intent = new Intent(this, HomeActivity.class);
            intent.setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP);
            startActivity(intent);
        });

        if (navProfil != null) navProfil.setOnClickListener(v -> {
            startActivity(new Intent(this, ProfilActivity.class));
        });

        if (navFakultas != null) navFakultas.setOnClickListener(v -> {
            startActivity(new Intent(this, FakultasActivity.class));
        });

        if (navFasilitas != null) navFasilitas.setOnClickListener(v -> {
            startActivity(new Intent(this, FasilitasActivity.class));
        });

        // Pasang fitur zoom popup untuk semua gambar konten
        setupZoomableImages();
    }

    private void setupZoomableImages() {
        int[] imageIds = {
                R.id.imgBannerPendaftaran,
                R.id.imgPersyaratanAkademik,
                R.id.imgPersyaratanDkv,
                R.id.imgPersyaratanFilm,
                R.id.imgPersyaratanHotel,
                R.id.imgProsedurPendaftaran,
                R.id.imgCatatanBagi
        };

        for (int id : imageIds) {
            ImageView img = findViewById(id);
            if (img != null) {
                ImagePopupHelper.makeZoomable(this, img);
            }
        }
    }
}

package com.example.umnapps;

import android.content.Context;
import android.graphics.Matrix;
import android.graphics.PointF;
import android.util.AttributeSet;
import android.view.GestureDetector;
import android.view.MotionEvent;
import android.view.ScaleGestureDetector;
import androidx.appcompat.widget.AppCompatImageView;

public class ZoomableImageView extends AppCompatImageView {

    private Matrix matrix = new Matrix();
    private float[] matrixValues = new float[9];

    // Zoom state
    private float minScale = 1f;
    private float maxScale = 5f;
    private float currentScale = 1f;

    // Gesture detectors
    private ScaleGestureDetector scaleDetector;
    private GestureDetector gestureDetector;

    // Drag state
    private PointF lastTouch = new PointF();
    private int activePointerId = -1;
    private boolean isDragging = false;

    // View dimensions
    private int viewWidth, viewHeight;
    private float originalWidth, originalHeight;
    private boolean isInitialized = false;

    public ZoomableImageView(Context context) {
        super(context);
        init(context);
    }

    public ZoomableImageView(Context context, AttributeSet attrs) {
        super(context, attrs);
        init(context);
    }

    public ZoomableImageView(Context context, AttributeSet attrs, int defStyle) {
        super(context, attrs, defStyle);
        init(context);
    }

    private void init(Context context) {
        setScaleType(ScaleType.MATRIX);

        scaleDetector = new ScaleGestureDetector(context, new ScaleGestureDetector.SimpleOnScaleGestureListener() {
            @Override
            public boolean onScale(ScaleGestureDetector detector) {
                float scaleFactor = detector.getScaleFactor();
                float newScale = currentScale * scaleFactor;

                if (newScale >= minScale && newScale <= maxScale) {
                    currentScale = newScale;
                    matrix.postScale(scaleFactor, scaleFactor, detector.getFocusX(), detector.getFocusY());
                    constrainMatrix();
                    setImageMatrix(matrix);
                }
                return true;
            }
        });

        gestureDetector = new GestureDetector(context, new GestureDetector.SimpleOnGestureListener() {
            @Override
            public boolean onDoubleTap(MotionEvent e) {
                if (currentScale > minScale) {
                    // Reset to fit
                    resetZoom();
                } else {
                    // Zoom to 2.5x at tap point
                    float targetScale = 2.5f;
                    float scaleFactor = targetScale / currentScale;
                    currentScale = targetScale;
                    matrix.postScale(scaleFactor, scaleFactor, e.getX(), e.getY());
                    constrainMatrix();
                    setImageMatrix(matrix);
                }
                return true;
            }
        });
    }

    @Override
    protected void onSizeChanged(int w, int h, int oldw, int oldh) {
        super.onSizeChanged(w, h, oldw, oldh);
        viewWidth = w;
        viewHeight = h;
        if (!isInitialized) {
            initializeMatrix();
        }
    }

    private void initializeMatrix() {
        if (getDrawable() == null) return;

        originalWidth = getDrawable().getIntrinsicWidth();
        originalHeight = getDrawable().getIntrinsicHeight();

        // Fit image to view (fit center)
        float scaleX = (float) viewWidth / originalWidth;
        float scaleY = (float) viewHeight / originalHeight;
        float scale = Math.min(scaleX, scaleY);

        float dx = (viewWidth - originalWidth * scale) / 2f;
        float dy = (viewHeight - originalHeight * scale) / 2f;

        matrix.reset();
        matrix.postScale(scale, scale);
        matrix.postTranslate(dx, dy);
        setImageMatrix(matrix);

        minScale = scale;
        currentScale = scale;
        isInitialized = true;
    }

    public void resetZoom() {
        isInitialized = false;
        initializeMatrix();
    }

    @Override
    public boolean onTouchEvent(MotionEvent event) {
        scaleDetector.onTouchEvent(event);
        gestureDetector.onTouchEvent(event);

        switch (event.getActionMasked()) {
            case MotionEvent.ACTION_DOWN:
                activePointerId = event.getPointerId(0);
                lastTouch.set(event.getX(), event.getY());
                isDragging = true;
                getParent().requestDisallowInterceptTouchEvent(true);
                break;

            case MotionEvent.ACTION_MOVE:
                if (isDragging && !scaleDetector.isInProgress()) {
                    int pointerIndex = event.findPointerIndex(activePointerId);
                    if (pointerIndex >= 0) {
                        float x = event.getX(pointerIndex);
                        float y = event.getY(pointerIndex);
                        float dx = x - lastTouch.x;
                        float dy = y - lastTouch.y;

                        if (currentScale > minScale) {
                            matrix.postTranslate(dx, dy);
                            constrainMatrix();
                            setImageMatrix(matrix);
                        }

                        lastTouch.set(x, y);
                    }
                }
                break;

            case MotionEvent.ACTION_UP:
            case MotionEvent.ACTION_CANCEL:
                activePointerId = -1;
                isDragging = false;
                break;

            case MotionEvent.ACTION_POINTER_UP:
                int pointerIndex = event.getActionIndex();
                int pointerId = event.getPointerId(pointerIndex);
                if (pointerId == activePointerId) {
                    int newPointerIndex = pointerIndex == 0 ? 1 : 0;
                    if (newPointerIndex < event.getPointerCount()) {
                        lastTouch.set(event.getX(newPointerIndex), event.getY(newPointerIndex));
                        activePointerId = event.getPointerId(newPointerIndex);
                    }
                }
                break;
        }
        return true;
    }

    private void constrainMatrix() {
        if (getDrawable() == null) return;

        matrix.getValues(matrixValues);
        float transX = matrixValues[Matrix.MTRANS_X];
        float transY = matrixValues[Matrix.MTRANS_Y];
        float scaleX = matrixValues[Matrix.MSCALE_X];

        float scaledWidth = originalWidth * scaleX;
        float scaledHeight = originalHeight * scaleX;

        float maxTransX, minTransX, maxTransY, minTransY;

        if (scaledWidth <= viewWidth) {
            minTransX = maxTransX = (viewWidth - scaledWidth) / 2f;
        } else {
            minTransX = viewWidth - scaledWidth;
            maxTransX = 0;
        }

        if (scaledHeight <= viewHeight) {
            minTransY = maxTransY = (viewHeight - scaledHeight) / 2f;
        } else {
            minTransY = viewHeight - scaledHeight;
            maxTransY = 0;
        }

        float dx = 0, dy = 0;
        if (transX < minTransX) dx = minTransX - transX;
        else if (transX > maxTransX) dx = maxTransX - transX;

        if (transY < minTransY) dy = minTransY - transY;
        else if (transY > maxTransY) dy = maxTransY - transY;

        matrix.postTranslate(dx, dy);
    }
}
